// ===== HALAMAN OCR KK & KTP (standalone, khusus admin, harus online) =====
// Catatan: hasil OCR bersifat bantu-baca, TIDAK dijamin 100% akurat.
// Semua field ditampilkan sebagai input yang bisa dikoreksi manual.
//
// Halaman ini TIDAK memuat app.min.js (mesin kalkulator utama) supaya
// tidak menduplikasi logika Asisten PPL -- hanya membaca/menulis
// langsung ke localStorage key yang sama ("se2026_respondenDB", dst.)
// yang dipakai assistencalc.html, lalu dorong sinkron ke server dengan
// format yang sama seperti pushDataSinkron di app.min.js.

let _dokumenState = { kk: null, ktpList: [], noMeteranListrik: "" };
let _respondenTerpilih = "";

function _getKodeDeviceDokumen(){
  const kode = localStorage.getItem("se2026_kode_aktif_v1") || "";
  const device = localStorage.getItem("se2026_device_uuid_v1") || "";
  return { kode, device };
}

// ---- Data layer minimal (baca/tulis localStorage yang sama dengan app utama) ----
function _muatRespondenDBLokal(){
  try { return JSON.parse(localStorage.getItem("se2026_respondenDB") || "{}"); } catch(e){ return {}; }
}
function _simpanRespondenDBLokal(db){
  localStorage.setItem("se2026_respondenDB", JSON.stringify(db));
}
async function _pushSyncDariHalamanIni(){
  const { kode, device } = _getKodeDeviceDokumen();
  if(!kode || !device || !navigator.onLine) return;
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;
  try{
    const respondenDB = _muatRespondenDBLokal();
    let riwayat = []; let slsDB = [];
    try { riwayat = JSON.parse(localStorage.getItem("se2026_riwayat") || "[]"); } catch(e){}
    try { slsDB = JSON.parse(localStorage.getItem("se2026_slsDB") || "[]"); } catch(e){}
    const payload = { _meta:{app:"Asisten Petugas SE2026", exportedAt:(new Date).toISOString(), version:2}, respondenDB, riwayat, slsDB };
    const body = JSON.stringify({ action:"upload", kode, device, data: JSON.stringify(payload) });
    await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
  }catch(e){ /* gagal sync -> biarkan, data tetap tersimpan lokal */ }
}

// ---- Pilih responden yang mau dilekatkan datanya ----
function _renderPilihResponden(){
  const sel = document.getElementById("pilihResponden");
  if(!sel) return;
  const db = _muatRespondenDBLokal();
  const keys = Object.keys(db);
  if(!keys.length){
    sel.innerHTML = '<option value="">(belum ada responden tersimpan di perangkat ini)</option>';
    _respondenTerpilih = "";
    return;
  }
  sel.innerHTML = keys.map(k => `<option value="${k}">${(db[k].nama||k)}</option>`).join("");
  if(!_respondenTerpilih || !db[_respondenTerpilih]) _respondenTerpilih = keys[0];
  sel.value = _respondenTerpilih;
}
function pilihResponden(key){
  _respondenTerpilih = key;
  renderDokumenTab();
}

// ---- Kompres gambar di browser sebelum dikirim (hemat kuota & waktu) ----
function _kompresGambar(file, maxWidth){
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(1, (maxWidth || 1400) / img.width);
        const canvas = document.createElement("canvas");
        canvas.width = Math.round(img.width * scale);
        canvas.height = Math.round(img.height * scale);
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL("image/jpeg", 0.72);
        resolve(dataUrl.split(",")[1]);
      };
      img.onerror = reject;
      img.src = e.target.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

async function _panggilOcrScan(base64, jenis, namaFile){
  const { kode, device } = _getKodeDeviceDokumen();
  if(!kode || !device){ showToast("⚠️ Belum login, tidak bisa scan dokumen"); return null; }
  if(!navigator.onLine){ showToast("⚠️ Butuh koneksi internet untuk scan OCR"); return null; }
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return null;

  const body = JSON.stringify({ action:"ocrscan", kode, device, jenis, mimeType:"image/jpeg", namaFile, imageBase64: base64 });
  const res = await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
  return await res.json();
}

// ---- KK ----
let _fileFotoKKBase64 = null;
function pilihFotoKK(ev){
  const file = ev.target.files && ev.target.files[0];
  if(!file) return;
  const prev = document.getElementById("previewFotoKK");
  const url = URL.createObjectURL(file);
  if(prev) prev.innerHTML = `<img src="${url}" style="max-width:100%;border-radius:8px;border:1px solid var(--copper)">`;
  const btn = document.getElementById("btnScanKK");
  if(btn){ btn.disabled = true; btn.textContent = "⏳ Menyiapkan gambar..."; }
  _kompresGambar(file, 1600).then(b64 => {
    _fileFotoKKBase64 = b64;
    if(btn){ btn.disabled = false; btn.textContent = "🔍 Scan & Ekstrak Data KK"; }
  }).catch(() => {
    if(btn){ btn.disabled = false; btn.textContent = "🔍 Scan & Ekstrak Data KK"; }
    showToast("⚠️ Gagal memproses gambar");
  });
}

async function scanKK(){
  if(!_fileFotoKKBase64){ showToast("⚠️ Pilih foto KK dulu"); return; }
  const status = document.getElementById("statusScanKK");
  const btn = document.getElementById("btnScanKK");
  if(status) status.textContent = "⏳ Mengunggah & memindai (bisa 10-30 detik)...";
  if(btn) btn.disabled = true;
  try{
    const hasil = await _panggilOcrScan(_fileFotoKKBase64, "kk", "KK_"+Date.now()+".jpg");
    if(!hasil){ if(status) status.textContent = ""; if(btn) btn.disabled = false; return; }
    if(!hasil.success){
      if(status) status.textContent = "❌ " + (hasil.message || "Gagal scan KK");
      if(btn) btn.disabled = false;
      return;
    }
    const f = hasil.fields || {};
    _dokumenState.kk = {
      nomor: f.nomorKK || "",
      kepalaKeluarga: f.kepalaKeluarga || "",
      alamat: f.alamat || "",
      anggota: (f.anggota || []).map(a => ({
        nik: a.nik || "",
        nama: "",
        namaBarisMentah: a.namaBaris || "",
        pendidikanKK: a.pendidikanTerdeteksi || "",
        pendidikanAktual: ""
      })),
      teksMentah: hasil.text || "",
      fileUrl: hasil.fileUrl || ""
    };
    _isiFormKK();
    if(status) status.textContent = "✅ Scan selesai. Cek & koreksi data di bawah sebelum disimpan.";
  }catch(e){
    if(status) status.textContent = "❌ Gagal terhubung ke server saat scan.";
  }
  if(btn) btn.disabled = false;
}

function _isiFormKK(){
  const kk = _dokumenState.kk;
  if(!kk) return;
  document.getElementById("hasilKK").style.display = "block";
  document.getElementById("kkNomor").value = kk.nomor || "";
  document.getElementById("kkKepalaKeluarga").value = kk.kepalaKeluarga || "";
  document.getElementById("kkAlamat").value = kk.alamat || "";
  document.getElementById("kkTeksMentah").textContent = kk.teksMentah || "(kosong)";
  _renderKkAnggotaList();
  _renderPendidikanTable();
  _renderKtpSlotList();
}

function _renderKkAnggotaList(){
  const el = document.getElementById("kkAnggotaList");
  if(!el) return;
  const kk = _dokumenState.kk;
  if(!kk || !kk.anggota.length){ el.innerHTML = '<div class="hint">Tidak ada baris anggota terdeteksi otomatis — cek teks mentah OCR, tambahkan manual kalau perlu.</div>'; return; }
  el.innerHTML = kk.anggota.map((a, i) => `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px;margin-bottom:8px">
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">NAMA ANGGOTA (isi manual dari baris OCR di bawah)</label><div class="input-wrap"><input type="text" value="${a.nama}" oninput="_updateAnggotaKK(${i},'nama',this.value)" placeholder="Isi nama sesuai baris OCR"></div></div>
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">NIK</label><div class="input-wrap"><input type="text" value="${a.nik}" oninput="_updateAnggotaKK(${i},'nik',this.value)"></div></div>
      <div class="hint" style="font-size:11px">Baris OCR asli: <i>${a.namaBarisMentah || "-"}</i></div>
    </div>
  `).join("");
}
function _updateAnggotaKK(i, field, val){
  if(!_dokumenState.kk || !_dokumenState.kk.anggota[i]) return;
  _dokumenState.kk.anggota[i][field] = val;
  if(field === "nama") _renderPendidikanTable();
}

// ---- KTP per anggota ----
function tambahSlotKTP(){
  if(!_dokumenState.kk){ showToast("⚠️ Scan KK dulu sebelum menambah foto KTP"); return; }
  _dokumenState.ktpList.push({ anggotaIdx: 0, base64: null, fields: null, teksMentah: "", fileUrl: "", perbedaan: [] });
  _renderKtpSlotList();
}
function _renderKtpSlotList(){
  const el = document.getElementById("ktpSlotList");
  if(!el) return;
  const kk = _dokumenState.kk;
  const opsiAnggota = (kk && kk.anggota.length) ? kk.anggota.map((a,i)=>`<option value="${i}">${a.nama || ("Anggota #"+(i+1))}</option>`).join("") : '<option value="0">(scan KK dulu)</option>';
  el.innerHTML = _dokumenState.ktpList.map((slot, i) => `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px;margin-bottom:10px">
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">UNTUK ANGGOTA</label><select onchange="_setAnggotaSlotKTP(${i},this.value)" style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--copper);background:var(--card);color:var(--text)">${opsiAnggota}</select></div>
      <div class="input-wrap" style="padding:8px"><input type="file" accept="image/*" capture="environment" onchange="_pilihFotoKTP(${i},event)" style="width:100%;color:var(--text)"></div>
      <div id="previewKTP${i}" style="margin-top:6px"></div>
      <button class="add-btn" onclick="scanKTP(${i})" style="margin-top:8px">🔍 Scan &amp; Bandingkan dengan KK</button>
      <div id="hasilKTP${i}" style="margin-top:8px"></div>
      <button onclick="_hapusSlotKTP(${i})" style="margin-top:6px;background:none;border:none;color:var(--red);font-size:12px;cursor:pointer">🗑️ Hapus slot ini</button>
    </div>
  `).join("");
}
function _setAnggotaSlotKTP(i, val){ _dokumenState.ktpList[i].anggotaIdx = parseInt(val,10) || 0; }
function _hapusSlotKTP(i){ _dokumenState.ktpList.splice(i,1); _renderKtpSlotList(); }
function _pilihFotoKTP(i, ev){
  const file = ev.target.files && ev.target.files[0];
  if(!file) return;
  const prev = document.getElementById("previewKTP"+i);
  const url = URL.createObjectURL(file);
  if(prev) prev.innerHTML = `<img src="${url}" style="max-width:100%;border-radius:8px;border:1px solid var(--copper)">`;
  _kompresGambar(file, 1600).then(b64 => { _dokumenState.ktpList[i].base64 = b64; }).catch(()=>{ showToast("⚠️ Gagal memproses gambar KTP"); });
}
async function scanKTP(i){
  const slot = _dokumenState.ktpList[i];
  if(!slot || !slot.base64){ showToast("⚠️ Pilih foto KTP dulu"); return; }
  const hasilEl = document.getElementById("hasilKTP"+i);
  if(hasilEl) hasilEl.innerHTML = '<div class="hint">⏳ Memindai KTP...</div>';
  try{
    const hasil = await _panggilOcrScan(slot.base64, "ktp", "KTP_"+Date.now()+".jpg");
    if(!hasil || !hasil.success){
      if(hasilEl) hasilEl.innerHTML = `<div class="hint" style="color:var(--red)">❌ ${(hasil && hasil.message) || "Gagal scan KTP"}</div>`;
      return;
    }
    slot.fields = hasil.fields || {};
    slot.teksMentah = hasil.text || "";
    slot.fileUrl = hasil.fileUrl || "";
    _bandingkanKtpDenganKK(i);
  }catch(e){
    if(hasilEl) hasilEl.innerHTML = '<div class="hint" style="color:var(--red)">❌ Gagal terhubung ke server saat scan.</div>';
  }
}
function _bandingkanKtpDenganKK(i){
  const slot = _dokumenState.ktpList[i];
  const kk = _dokumenState.kk;
  const anggotaKK = kk ? kk.anggota[slot.anggotaIdx] : null;
  const f = slot.fields || {};
  const perbedaan = [];

  function bandingkan(labelTampil, nilaiKK, nilaiKTP){
    const a = (nilaiKK||"").toString().trim().toUpperCase();
    const b = (nilaiKTP||"").toString().trim().toUpperCase();
    if(!a || !b) return null;
    return a === b ? { label:labelTampil, sama:true, kk:nilaiKK, ktp:nilaiKTP } : { label:labelTampil, sama:false, kk:nilaiKK, ktp:nilaiKTP };
  }

  const cekNama = bandingkan("Nama", anggotaKK ? anggotaKK.nama : "", f.nama);
  const cekNIK = bandingkan("NIK", anggotaKK ? anggotaKK.nik : "", f.nik);
  [cekNama, cekNIK].forEach(c => { if(c) perbedaan.push(c); });
  slot.perbedaan = perbedaan;

  const hasilEl = document.getElementById("hasilKTP"+i);
  if(!hasilEl) return;
  const adaBeda = perbedaan.some(p => !p.sama);
  let html = `<div style="font-size:12px;padding:8px;border-radius:8px;background:${adaBeda ? "var(--red-bg)" : "var(--green-bg)"};border-left:3px solid ${adaBeda ? "var(--red)" : "var(--green)"}">`;
  html += adaBeda ? "⚠️ <b>Ada perbedaan data KK vs KTP:</b><br>" : "✅ Data KTP cocok dengan KK (untuk field yang bisa dibandingkan).<br>";
  if(perbedaan.length){
    perbedaan.forEach(p => {
      html += `${p.sama?"✅":"⚠️"} <b>${p.label}</b> — KK: "${p.kk}" | KTP: "${p.ktp}"<br>`;
    });
  } else {
    html += '<span class="hint">Belum ada nama/NIK di sisi KK untuk dibandingkan (isi manual dulu di daftar anggota KK).</span>';
  }
  html += `<div style="margin-top:6px">NIK KTP: <b>${f.nik||"-"}</b> · Nama: <b>${f.nama||"-"}</b> · TTL: <b>${f.tempatTglLahir||"-"}</b> · Alamat: <b>${f.alamat||"-"}</b></div>`;
  html += `</div>`;
  hasilEl.innerHTML = html;
}

// ---- Pendidikan (KK vs Aktual) ----
function _renderPendidikanTable(){
  const el = document.getElementById("pendidikanTable");
  if(!el) return;
  const kk = _dokumenState.kk;
  if(!kk || !kk.anggota.length){ el.innerHTML = '<div class="hint">Scan KK dulu supaya daftar anggota otomatis terisi.</div>'; return; }
  el.innerHTML = kk.anggota.map((a, i) => `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px;margin-bottom:8px">
      <div style="font-weight:700;font-size:13px;margin-bottom:6px">${a.nama || ("Anggota #"+(i+1))}</div>
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">PENDIDIKAN TERCATAT DI KK</label><div class="input-wrap"><input type="text" value="${a.pendidikanKK}" oninput="_updateAnggotaKK(${i},'pendidikanKK',this.value)"></div></div>
      <div class="field" style="margin-bottom:6px"><label style="font-size:10px">PENDIDIKAN SEBENARNYA (cek lapangan)</label><div class="input-wrap"><input type="text" value="${a.pendidikanAktual}" oninput="_updateAnggotaKK(${i},'pendidikanAktual',this.value)"></div></div>
      ${a.pendidikanKK && a.pendidikanAktual ? (a.pendidikanKK.trim().toUpperCase()===a.pendidikanAktual.trim().toUpperCase() ? '<div class="hint" style="color:var(--green)">✅ Sama dengan KK</div>' : '<div class="hint" style="color:var(--red)">⚠️ Berbeda dari catatan KK</div>') : ''}
    </div>
  `).join("");
}

// ---- Simpan & muat data dokumen ke/dari responden terpilih ----
function simpanDataDokumen(){
  if(!_respondenTerpilih){
    showToast("⚠️ Pilih responden dulu di dropdown atas");
    return;
  }
  const db = _muatRespondenDBLokal();
  if(!db[_respondenTerpilih]){
    showToast("⚠️ Responden tidak ditemukan (mungkin sudah dihapus di Asisten PPL)");
    return;
  }
  const meteran = (document.getElementById("noMeteranListrik")||{}).value || "";
  _dokumenState.noMeteranListrik = meteran;
  if(_dokumenState.kk){
    _dokumenState.kk.nomor = (document.getElementById("kkNomor")||{}).value || "";
    _dokumenState.kk.kepalaKeluarga = (document.getElementById("kkKepalaKeluarga")||{}).value || "";
    _dokumenState.kk.alamat = (document.getElementById("kkAlamat")||{}).value || "";
  }
  db[_respondenTerpilih].dokumenKK = _dokumenState.kk;
  db[_respondenTerpilih].dokumenKTP = _dokumenState.ktpList.map(s => ({ anggotaIdx:s.anggotaIdx, fields:s.fields, teksMentah:s.teksMentah, fileUrl:s.fileUrl, perbedaan:s.perbedaan }));
  db[_respondenTerpilih].noMeteranListrik = meteran;
  _simpanRespondenDBLokal(db);
  showToast("✅ Data dokumen tersimpan, sinkron ke server...");
  _pushSyncDariHalamanIni().then(() => showToast("✅ Tersinkron ke server"));
}

function renderDokumenTab(){
  _renderPilihResponden();
  const db = _muatRespondenDBLokal();
  if(!_respondenTerpilih || !db[_respondenTerpilih]){
    _dokumenState = { kk: null, ktpList: [], noMeteranListrik: "" };
  } else {
    const r = db[_respondenTerpilih];
    _dokumenState = {
      kk: r.dokumenKK || null,
      ktpList: r.dokumenKTP || [],
      noMeteranListrik: r.noMeteranListrik || ""
    };
  }
  const meteranEl = document.getElementById("noMeteranListrik");
  if(meteranEl) meteranEl.value = _dokumenState.noMeteranListrik || "";
  const hasilKKEl = document.getElementById("hasilKK");
  if(_dokumenState.kk){
    if(hasilKKEl) hasilKKEl.style.display = "block";
    _isiFormKK();
  } else {
    if(hasilKKEl) hasilKKEl.style.display = "none";
    _renderKtpSlotList();
    _renderPendidikanTable();
  }
}

window.pilihResponden = pilihResponden;
window.pilihFotoKK = pilihFotoKK;
window.scanKK = scanKK;
window.tambahSlotKTP = tambahSlotKTP;
window._setAnggotaSlotKTP = _setAnggotaSlotKTP;
window._hapusSlotKTP = _hapusSlotKTP;
window._pilihFotoKTP = _pilihFotoKTP;
window.scanKTP = scanKTP;
window._updateAnggotaKK = _updateAnggotaKK;
window.simpanDataDokumen = simpanDataDokumen;
window.renderDokumenTab = renderDokumenTab;

document.addEventListener('DOMContentLoaded', () => { try { renderDokumenTab(); } catch(e){} });
